import express from "express";

// src/modules/meals/meals.service.ts
var getAllMeals = async () => {
  return await prisma.meal.findMany({
    include: {
      provider: true,
      category: true
    }
  });
};
var getMealById = async (id) => {
  return await prisma.meal.findUnique({
    where: { id },
    include: {
      provider: true,
      category: true
    }
  });
};
var createMeal = async (data, userId) => {
  const provider = await prisma.providerProfile.findUnique({
    where: { userId }
  });
  if (!provider) {
    throw new Error("provider not found");
  }
  const result = await prisma.meal.create({
    data: {
      ...data,
      providerId: provider.id
    }
  });
  return result;
};
var updateMeal = async (mealId, data, userId) => {
  const provider = await prisma.providerProfile.findUnique({
    where: { userId }
  });
  if (!provider) {
    throw new Error("provider not found");
  }
  const meal = await prisma.meal.findUnique({
    where: { id: mealId }
  });
  if (!meal || meal.providerId !== provider.id) {
    throw new Error("Unathorized");
  }
  return prisma.meal.update({
    where: { id: mealId },
    data
  });
};
var deleteMeal = async (mealId, userId) => {
  const provider = await prisma.providerProfile.findUnique({
    where: { userId }
  });
  if (!provider) {
    throw new Error("provider not found");
  }
  ;
  const meal = await prisma.meal.findUnique({
    where: { id: mealId }
  });
  if (!meal || meal.providerId !== provider.id) {
    throw new Error("Unauthorized");
  }
  return prisma.meal.delete({
    where: { id: mealId }
  });
};
var getMyMeals = async (userId) => {
  const provider = await prisma.providerProfile.findUnique({
    where: { userId }
  });
  if (!provider) {
    throw new Error("provider not found");
  }
  return await prisma.meal.findMany({
    where: { providerId: provider.id }
  });
};
var mealService = {
  getAllMeals,
  getMealById,
  createMeal,
  updateMeal,
  deleteMeal,
  getMyMeals
};

// src/modules/meals/meals.controller.ts
var getAllMeals2 = async (req, res) => {
  try {
    const meals = await mealService.getAllMeals();
    res.status(200).json(meals);
  } catch (error) {
    res.status(500).json({
      message: "Something went wrong",
      error: error.message
    });
  }
};
var getMealById2 = async (req, res) => {
  try {
    const { mealId } = req.params;
    const meal = await mealService.getMealById(mealId);
    res.status(200).json(meal);
  } catch (error) {
    res.status(500).json({
      message: "Something went wrong",
      error: error.message
    });
  }
};
var createMeal2 = async (req, res) => {
  try {
    const user = req.user;
    const result = await mealService.createMeal(req.body, user?.id);
    res.status(201).json(result);
  } catch (error) {
    res.status(500).json({
      message: "Something went wrong",
      error: error.message
    });
  }
};
var updateMeal2 = async (req, res) => {
  try {
    const user = req.user;
    const { mealId } = req.params;
    const result = await mealService.updateMeal(mealId, req.body, user?.id);
    res.status(201).json(result);
  } catch (error) {
    res.status(500).json({
      message: "Something went wrong",
      error: error.message
    });
  }
};
var deleteMeal2 = async (req, res) => {
  try {
    const user = req.user;
    const { mealId } = req.params;
    const result = await mealService.deleteMeal(mealId, user?.id);
    res.status(201).json({
      message: "meal delete success!!",
      meal: result
    });
  } catch (error) {
    res.status(500).json({
      message: "Something went wrong",
      error: error.message
    });
  }
};
